#include <iostream>
#include <vector>

int largestIndex(const std::vector<int>& values) {
  if (values.empty()) {
    return -1;
  }

  std::size_t best = 0;
  for (std::size_t i = 1; i < values.size(); i++) {
    if (values[i] > values[best]) {
      best = i;
    }
  }

  return static_cast<int>(best);
}

int main() {
  std::cout << largestIndex({4, 9, 7}) << "\n";
}
